const trigger = $('New Lead Added').first().json;

// Get Summary Log runs first (listed first in fan-out from Run Workflow).
// $('Get Summary Log').all() returns [] when the sheet has no data rows,
// so this node always outputs exactly 1 item regardless of sheet state.
const summaryRows = $('Get Summary Log').all()
  .map(r => r.json)
  .filter(r => r && r.Company);

return [{
  json: {
    summaryRows,
    company: (trigger.Company || '').trim(),
    website: trigger.Website || '',
    contactName: trigger['Contact Name'] || '',
    role: trigger.Role || '',
    email: trigger.Email || ''
  }
}];

const { company, website, contactName, role, email, summaryRows } = $input.first().json;
const cutoff = Date.now() - (30 * 24 * 60 * 60 * 1000);

let isRecent = false;
if (summaryRows && summaryRows.length > 0) {
  isRecent = summaryRows.some(row => {
    const rowCompany = (row.Company || '').trim();
    if (rowCompany.toLowerCase() !== company.toLowerCase()) return false;
    if (!row.Recency) return false;
    return new Date(row.Recency).getTime() > cutoff;
  });
}

return [{ json: { isRecent, company, website, contactName, role, email } }];

