const raw = ($input.first().json.text || '').trim();
const trigger = $('New Lead Added').first().json;

let score = 5;
let rationale = 'Score could not be parsed from LLM output.';

try {
  const cleaned = raw.replace(/```(?:json)?\s*/gi, '').replace(/```\s*/g, '').trim();
  const parsed = JSON.parse(cleaned);
  score = Math.min(10, Math.max(1, parseInt(parsed.score, 10)));
  rationale = parsed.rationale || rationale;
} catch (e) {
  const scoreMatch = raw.match(/"score"\s*:\s*(\d+)/);
  const rationaleMatch = raw.match(/"rationale"\s*:\s*"([^"]+)"/);
  if (scoreMatch) score = Math.min(10, Math.max(1, parseInt(scoreMatch[1], 10)));
  if (rationaleMatch) rationale = rationaleMatch[1];
}

return [{
  json: {
    score,
    rationale,
    company: trigger.Company || '',
    website: trigger.Website || '',
    contactName: trigger['Contact Name'] || '',
    role: trigger.Role || '',
    email: trigger.Email || '',
    summary: $('Summarizer Chain').first().json.text || ''
  }
}];

const body = ($input.first().json.text || '').trim();
if (!body) {
  throw new Error(
    'Email Writer Chain returned an empty body for ' +
    $('Parse Score').first().json.company +
    ' — execution stopped before sending.'
  );
}
return $input.all();
